class Meal {
    private final String bun;
    private final int pattyCount;
    private final String cheese;
    private final String sauce;
    private final String size;
    private final double price;

    private Meal(Builder b) {
        this.bun = b.bun;
        this.pattyCount = b.pattyCount;
        this.cheese = b.cheese;
        this.sauce = b.sauce;
        this.size = b.size;
        this.price = b.price;
    }

    @Override
    public String toString() {
        return String.format("[MEAL] %s, %d patties, %s cheese, %s sauce, %s -- $%.2f",
            bun, pattyCount, cheese, sauce, size, price);
    }

    public static class Builder {
        private String bun;
        private int pattyCount;
        private String cheese = "None";
        private String sauce = "None";
        private String size = "Regular";
        private double price;

        public Builder setBun(String bun) { this.bun = bun; return this; }
        public Builder setPattyCount(int count) { this.pattyCount = count; return this; }
        public Builder setCheese(String cheese) { this.cheese = cheese; return this; }
        public Builder setSauce(String sauce) { this.sauce = sauce; return this; }
        public Builder setSize(String size) { this.size = size; return this; }
        public Builder setPrice(double price) { this.price = price; return this; }

        public Meal build() {
            if (bun == null || bun.isEmpty()) throw new IllegalStateException("Bun is required");
            if (pattyCount < 1) throw new IllegalStateException("At least 1 patty required");
            if (price <= 0) throw new IllegalStateException("Price must be positive");
            return new Meal(this);
        }
    }
}

public class Main {
    public static void main(String[] args) {
        Meal burger = new Meal.Builder()
            .setBun("Sesame")
            .setPattyCount(2)
            .setCheese("Cheddar")
            .setSauce("BBQ")
            .setSize("Large")
            .setPrice(11.50)
            .build();
        System.out.println(burger);

        Meal simple = new Meal.Builder()
            .setBun("Plain")
            .setPattyCount(1)
            .setPrice(5.99)
            .build();
        System.out.println(simple);
    }
}

