import java.util.ArrayList;
import java.util.List;

class Notification {
    private final String channel;
    private final String recipient;
    private final String subject;
    private final String body;
    private final String priority;
    private final int attachments;

    private Notification(Builder b) {
        this.channel = b.channel;
        this.recipient = b.recipient;
        this.subject = b.subject;
        this.body = b.body;
        this.priority = b.priority;
        this.attachments = b.attachments;
    }

    @Override
    public String toString() {
        return String.format("[%s] To: %s | Subject: %s | Priority: %s | Attachments: %d",
            channel, recipient, subject != null ? subject : "N/A", priority, attachments);
    }

    public static class Builder {
        private String channel;
        private String recipient;
        private String subject;
        private String body;
        private String priority = "MEDIUM";
        private int attachments = 0;

        public Builder setChannel(String channel) { this.channel = channel; return this; }
        public Builder setRecipient(String recipient) { this.recipient = recipient; return this; }
        public Builder setSubject(String subject) { this.subject = subject; return this; }
        public Builder setBody(String body) { this.body = body; return this; }
        public Builder setPriority(String priority) { this.priority = priority; return this; }
        public Builder setAttachments(int count) { this.attachments = count; return this; }

        public Notification build() {
            List<String> errors = new ArrayList<>();
            if (channel == null) errors.add("Channel is required");
            if (recipient == null) errors.add("Recipient is required");

            if (errors.isEmpty() && channel.equals("EMAIL")) {
                if (subject == null || subject.isEmpty()) errors.add("EMAIL requires subject");
                if (!recipient.contains("@")) errors.add("EMAIL recipient must contain @");
            }
            if (errors.isEmpty() && channel.equals("SMS")) {
                if (body != null && body.length() > 160) errors.add("SMS body max 160 chars");
                if (!recipient.matches("\\d+")) errors.add("SMS recipient must be digits only");
            }
            if (errors.isEmpty() && channel.equals("PUSH")) {
                if (priority == null) errors.add("PUSH requires priority");
            }

            if (!errors.isEmpty()) {
                throw new IllegalStateException("Validation failed: " + String.join(", ", errors));
            }
            return new Notification(this);
        }
    }
}

public class Main {
    public static void main(String[] args) {
        Notification email = new Notification.Builder()
            .setChannel("EMAIL")
            .setRecipient("user@example.com")
            .setSubject("Order Shipped")
            .setBody("Your order is on the way!")
            .setAttachments(1)
            .build();
        System.out.println(email);

        Notification sms = new Notification.Builder()
            .setChannel("SMS")
            .setRecipient("5551234567")
            .setBody("Your OTP is 4829")
            .build();
        System.out.println(sms);

        Notification push = new Notification.Builder()
            .setChannel("PUSH")
            .setRecipient("device-token-abc")
            .setPriority("HIGH")
            .setBody("Flash sale!")
            .build();
        System.out.println(push);

        try {
            new Notification.Builder()
                .setChannel("EMAIL")
                .setRecipient("no-at-sign")
                .build();
        } catch (IllegalStateException e) {
            System.out.println("[ERROR] " + e.getMessage());
        }
    }
}

