#include <iostream>
#include <string>
#include <vector>
#include <stdexcept>
#include <algorithm>
#include <regex>
using namespace std;

class Notification {
    string channel;
    string recipient;
    string subject;
    string body;
    string priority;
    int attachments;

    Notification(string ch, string r, string sub, string bd, string pr, int att)
        : channel(ch), recipient(r), subject(sub), body(bd), priority(pr), attachments(att) {}

public:
    class Builder;
    friend class Builder;

    friend ostream& operator<<(ostream& os, const Notification& n) {
        os << "[" << n.channel << "] To: " << n.recipient
           << " | Subject: " << (n.subject.empty() ? "N/A" : n.subject)
           << " | Priority: " << n.priority
           << " | Attachments: " << n.attachments;
        return os;
    }
};

class Notification::Builder {
    string channel_;
    string recipient_;
    string subject_;
    string body_;
    string priority_ = "MEDIUM";
    int attachments_ = 0;

public:
    Builder& setChannel(const string& c) { channel_ = c; return *this; }
    Builder& setRecipient(const string& r) { recipient_ = r; return *this; }
    Builder& setSubject(const string& s) { subject_ = s; return *this; }
    Builder& setBody(const string& b) { body_ = b; return *this; }
    Builder& setPriority(const string& p) { priority_ = p; return *this; }
    Builder& setAttachments(int a) { attachments_ = a; return *this; }

    Notification build() {
        vector<string> errors;
        if (channel_.empty()) errors.push_back("Channel is required");
        if (recipient_.empty()) errors.push_back("Recipient is required");

        if (errors.empty() && channel_ == "EMAIL") {
            if (subject_.empty()) errors.push_back("EMAIL requires subject");
            if (recipient_.find('@') == string::npos) errors.push_back("EMAIL recipient must contain @");
        }
        if (errors.empty() && channel_ == "SMS") {
            if (body_.length() > 160) errors.push_back("SMS body max 160 chars");
            if (!regex_match(recipient_, regex("\\d+"))) errors.push_back("SMS recipient must be digits");
        }

        if (!errors.empty()) {
            string msg = "Validation failed: ";
            for (size_t i = 0; i < errors.size(); i++) {
                if (i > 0) msg += ", ";
                msg += errors[i];
            }
            throw invalid_argument(msg);
        }
        return Notification(channel_, recipient_, subject_, body_, priority_, attachments_);
    }
};

int main() {
    auto email = Notification::Builder()
        .setChannel("EMAIL")
        .setRecipient("user@example.com")
        .setSubject("Order Shipped")
        .setBody("Your order is on the way!")
        .setAttachments(1)
        .build();
    cout << email << endl;

    auto sms = Notification::Builder()
        .setChannel("SMS")
        .setRecipient("5551234567")
        .setBody("Your OTP is 4829")
        .build();
    cout << sms << endl;

    try {
        Notification::Builder()
            .setChannel("EMAIL")
            .setRecipient("no-at-sign")
            .build();
    } catch (const invalid_argument& e) {
        cout << "[ERROR] " << e.what() << endl;
    }

    return 0;
}

