class PaymentRequest {
    private final double amount;
    private final String currency;
    private final String method;
    private final String cardNumber;
    private final String expiry;
    private final String cvv;
    private final String vpa;
    private final String accountNumber;
    private final String ifscCode;

    private PaymentRequest(Builder b) {
        this.amount = b.amount;
        this.currency = b.currency;
        this.method = b.method;
        this.cardNumber = b.cardNumber;
        this.expiry = b.expiry;
        this.cvv = b.cvv;
        this.vpa = b.vpa;
        this.accountNumber = b.accountNumber;
        this.ifscCode = b.ifscCode;
    }

    public String toSummary() {
        StringBuilder sb = new StringBuilder();
        sb.append(String.format("[%s] %.2f %s", method, amount, currency));
        switch (method) {
            case "CREDIT_CARD":
                sb.append(" | Card: ****-****-****-" + cardNumber.substring(12));
                sb.append(" | Exp: " + expiry + " | CVV: ***");
                break;
            case "UPI":
                sb.append(" | VPA: " + vpa);
                break;
            case "BANK_TRANSFER":
                String masked = "****" + accountNumber.substring(Math.max(0, accountNumber.length() - 4));
                sb.append(" | Acct: " + masked + " | IFSC: " + ifscCode);
                break;
        }
        return sb.toString();
    }

    public static class Builder {
        private double amount;
        private String currency;
        private String method;
        private String cardNumber;
        private String expiry;
        private String cvv;
        private String vpa;
        private String accountNumber;
        private String ifscCode;

        public Builder setAmount(double amount) { this.amount = amount; return this; }
        public Builder setCurrency(String currency) { this.currency = currency; return this; }
        public Builder setMethod(String method) { this.method = method; return this; }
        public Builder setCardNumber(String cardNumber) { this.cardNumber = cardNumber; return this; }
        public Builder setExpiry(String expiry) { this.expiry = expiry; return this; }
        public Builder setCvv(String cvv) { this.cvv = cvv; return this; }
        public Builder setVpa(String vpa) { this.vpa = vpa; return this; }
        public Builder setAccountNumber(String acct) { this.accountNumber = acct; return this; }
        public Builder setIfscCode(String ifsc) { this.ifscCode = ifsc; return this; }

        public PaymentRequest build() {
            if (amount <= 0) throw new IllegalStateException("Amount must be positive");
            if (currency == null || currency.isEmpty()) throw new IllegalStateException("Currency required");
            if (method == null) throw new IllegalStateException("Payment method required");

            switch (method) {
                case "CREDIT_CARD":
                    if (cardNumber == null || !cardNumber.matches("\\d{16}"))
                        throw new IllegalStateException("Card number must be 16 digits");
                    if (expiry == null || !expiry.matches("\\d{2}/\\d{2}"))
                        throw new IllegalStateException("Expiry must be MM/YY");
                    if (cvv == null || !cvv.matches("\\d{3}"))
                        throw new IllegalStateException("CVV must be 3 digits");
                    break;
                case "UPI":
                    if (vpa == null || !vpa.contains("@"))
                        throw new IllegalStateException("VPA must contain @");
                    break;
                case "BANK_TRANSFER":
                    if (accountNumber == null || accountNumber.isEmpty())
                        throw new IllegalStateException("Account number required");
                    if (ifscCode == null || !ifscCode.matches("[A-Z]{4}\\d{7}"))
                        throw new IllegalStateException("IFSC must be 4 letters + 7 digits");
                    break;
                default:
                    throw new IllegalStateException("Unknown method: " + method);
            }
            return new PaymentRequest(this);
        }
    }
}

public class Main {
    public static void main(String[] args) {
        PaymentRequest card = new PaymentRequest.Builder()
            .setAmount(2499.99)
            .setCurrency("USD")
            .setMethod("CREDIT_CARD")
            .setCardNumber("4111111111111234")
            .setExpiry("12/25")
            .setCvv("789")
            .build();
        System.out.println(card.toSummary());

        PaymentRequest upi = new PaymentRequest.Builder()
            .setAmount(999.00)
            .setCurrency("INR")
            .setMethod("UPI")
            .setVpa("ravi@upi")
            .build();
        System.out.println(upi.toSummary());

        PaymentRequest bank = new PaymentRequest.Builder()
            .setAmount(50000.00)
            .setCurrency("INR")
            .setMethod("BANK_TRANSFER")
            .setAccountNumber("1234567890")
            .setIfscCode("HDFC0001234")
            .build();
        System.out.println(bank.toSummary());

        try {
            new PaymentRequest.Builder()
                .setAmount(100.00)
                .setCurrency("USD")
                .setMethod("CREDIT_CARD")
                .setCardNumber("123")
                .build();
        } catch (IllegalStateException e) {
            System.out.println("[ERROR] " + e.getMessage());
        }
    }
}

